u}^{y} \end{bmatrix} 
onumber\[6pt] & = \sum_j -i\, oldsymbol\epsilon_{j,\mathbf{q}
u}^{x*}\, oldsymbol\epsilon_{j,\mathbf{q}
u}^{y} +i\, oldsymbol\epsilon_{j,\mathbf{q}
u}^{x}\, oldsymbol\epsilon_{j,\mathbf{q}
